CREATE TABLE game_recommender.users ( id UUID PRIMARY KEY, steam_id BIGINT NOT NULL UNIQUE, is_active BOOLEAN NOT NULL, role VARCHAR(255), created_at TIMESTAMP(6) NOT NULL, updated_at TIMESTAMP(6) NOT NULL );
-- Check role ALTER TABLE game_recommender.users ADD CONSTRAINT ck_users_role CHECK (role IN ('GUEST', 'USER'));
CREATE INDEX idx_users_steam_id ON game_recommender.users (steam_id);
